"""Evaluator factories for external processes and HTTP services.

These bridge external scoring systems to gepa's evaluator protocol:
    evaluator(candidate: str) -> float | tuple[float, dict]
"""

from __future__ import annotations

import json
import math
import subprocess
from typing import Any, Callable

import httpx


def command_evaluator(
    command: list[str],
    *,
    timeout: float = 30.0,
    cwd: str | None = None,
) -> Callable[[str], tuple[float, dict[str, Any]]]:
    """Create an evaluator that runs a shell command.

    The command receives JSON on stdin: {"candidate": "<text>"}
    and must output JSON on stdout with at least a "score" field.
    Additional fields become side information for gepa's reflection.

    Args:
        command: Command and arguments to execute.
        timeout: Max seconds to wait for the command.
        cwd: Working directory used to run the command.

    Returns:
        An evaluator function compatible with gepa.
    """

    def evaluate(candidate: str) -> tuple[float, dict[str, Any]]:
        payload = json.dumps({"candidate": candidate})
        try:
            proc = subprocess.run(
                command,
                input=payload,
                capture_output=True,
                text=True,
                timeout=timeout,
                cwd=cwd,
            )
        except FileNotFoundError:
            return 0.0, {"error": f"Command executable not found: {command[0]}"}
        except subprocess.TimeoutExpired:
            return 0.0, {"error": f"Command timed out after {timeout}s"}
        except OSError as e:
            return 0.0, {"error": f"Command failed to start: {e}"}

        if proc.returncode != 0:
            return 0.0, {
                "error": f"Command exited with code {proc.returncode}",
                "stderr": proc.stderr.strip(),
            }

        try:
            result = json.loads(proc.stdout)
        except json.JSONDecodeError:
            return 0.0, {
                "error": "Command output is not valid JSON",
                "stdout": proc.stdout.strip(),
            }

        return _parse_evaluator_result(result)

    return evaluate


def http_evaluator(
    url: str,
    *,
    timeout: float = 30.0,
    headers: dict[str, str] | None = None,
) -> Callable[[str], tuple[float, dict[str, Any]]]:
    """Create an evaluator that calls an HTTP endpoint.

    Sends a POST request with JSON body: {"candidate": "<text>"}
    Expects a JSON response with at least a "score" field.

    Args:
        url: HTTP endpoint URL.
        timeout: Max seconds to wait for the response.
        headers: Optional HTTP headers.

    Returns:
        An evaluator function compatible with gepa.
    """

    def evaluate(candidate: str) -> tuple[float, dict[str, Any]]:
        payload = {"candidate": candidate}
        try:
            resp = httpx.post(
                url,
                json=payload,
                timeout=timeout,
                headers=headers or {},
            )
            resp.raise_for_status()
        except httpx.TimeoutException:
            return 0.0, {"error": f"HTTP request timed out after {timeout}s"}
        except httpx.HTTPStatusError as e:
            return 0.0, {"error": f"HTTP {e.response.status_code}: {e.response.text}"}
        except httpx.RequestError as e:
            return 0.0, {"error": f"HTTP request failed: {e}"}

        try:
            result = resp.json()
        except (json.JSONDecodeError, ValueError):
            return 0.0, {
                "error": "Response is not valid JSON",
                "body": resp.text[:500],
            }

        return _parse_evaluator_result(result)

    return evaluate


def validate_evaluator_payload(result: Any) -> str | None:
    """Validate an evaluator JSON payload.

    Returns None if valid, or a human-readable error string.
    This is the shared validation used by both CLI preflight and runtime checking.
    """
    if not isinstance(result, dict):
        return "evaluator output must be a JSON object"
    if "score" not in result:
        return "evaluator output missing required 'score' field"
    raw_score = result.get("score")
    try:
        score = float(raw_score)
    except (TypeError, ValueError):
        return "evaluator output 'score' must be numeric"
    if not math.isfinite(score):
        return "evaluator output 'score' must be finite"
    if score < 0.0 or score > 1.0:
        return "evaluator output 'score' must be between 0.0 and 1.0"
    return None


def _parse_evaluator_result(result: Any) -> tuple[float, dict[str, Any]]:
    """Validate evaluator JSON payload and extract score + side information."""
    if not isinstance(result, dict):
        return 0.0, {
            "error": "Evaluator output must be a JSON object",
            "received_type": type(result).__name__,
        }

    side_info = {k: v for k, v in result.items() if k != "score"}
    if "score" not in result:
        side_info["error"] = "Evaluator output missing required 'score' field"
        return 0.0, side_info

    raw_score = result["score"]
    try:
        score = float(raw_score)
    except (TypeError, ValueError):
        side_info["error"] = "Evaluator 'score' must be numeric"
        side_info["score"] = raw_score
        return 0.0, side_info

    if not math.isfinite(score):
        side_info["error"] = "Evaluator 'score' must be finite"
        side_info["score"] = raw_score
        return 0.0, side_info

    if score < 0.0 or score > 1.0:
        side_info["error"] = "Evaluator 'score' must be between 0.0 and 1.0"
        side_info["score"] = raw_score
        return 0.0, side_info
    return score, side_info

"""Documentation drift guard for core contract terms."""

from __future__ import annotations

import json
import re
from pathlib import Path


REPO_ROOT = Path(__file__).resolve().parents[1]
DOC_PATHS = (
    Path("README.md"),
    Path("docs/mcp-protocol.md"),
    Path("docs/release-checklist.md"),
    Path("docs/final-readiness-review.md"),
)


def _read_text(path: Path) -> str:
    return (REPO_ROOT / path).read_text(encoding="utf-8")


def _combined_docs_text() -> str:
    return "\n".join(_read_text(path) for path in DOC_PATHS)


def _assert_contains_terms(*, text: str, terms: list[str], label: str) -> None:
    missing = [term for term in terms if term not in text]
    assert not missing, f"{label} is missing required terms: {', '.join(missing)}"


def _assert_source_defines_keys(*, source: str, keys: list[str], label: str) -> None:
    missing = [
        key for key in keys if re.search(rf'["\']{re.escape(key)}["\']\s*:', source) is None
    ]
    assert not missing, f"{label} is missing required keys: {', '.join(missing)}"


def test_intake_schema_fields_are_documented():
    docs_text = _combined_docs_text()
    required_fields = [
        "artifact_class",
        "quality_dimensions",
        "hard_constraints",
        "evaluation_pattern",
        "execution_mode",
        "evaluator_cwd",
    ]

    _assert_contains_terms(
        text=docs_text,
        terms=required_fields,
        label="docs",
    )


def test_optimize_output_keys_are_documented_and_in_runtime_contract():
    required_keys = [
        "best_artifact",
        "total_metric_calls",
        "score_summary",
        "top_diagnostics",
        "plateau_guidance",
        "evaluator_failure_signal",
    ]

    docs_text = _combined_docs_text()
    _assert_contains_terms(
        text=docs_text,
        terms=required_keys,
        label="docs",
    )

    result_contract_source = _read_text(Path("src/optimize_anything/result_contract.py"))
    _assert_source_defines_keys(
        source=result_contract_source,
        keys=required_keys,
        label="src/optimize_anything/result_contract.py",
    )


def test_cli_intake_flags_are_documented_and_in_runtime():
    required_flags = ["--intake-json", "--intake-file", "--evaluator-cwd"]

    docs_text = _combined_docs_text()
    _assert_contains_terms(
        text=docs_text,
        terms=required_flags,
        label="docs",
    )

    cli_source = _read_text(Path("src/optimize_anything/cli.py"))
    _assert_contains_terms(
        text=cli_source,
        terms=required_flags,
        label="src/optimize_anything/cli.py",
    )


def test_removed_server_artifacts_not_referenced_in_active_docs():
    docs_text = _combined_docs_text()
    forbidden_terms = ["optimize_anything.server", "tests/test_server.py"]
    for term in forbidden_terms:
        assert term not in docs_text, f"active docs still reference removed artifact: {term}"

# --- Plugin manifest tests ---


def _plugin_json() -> dict:
    path = REPO_ROOT / ".claude-plugin" / "plugin.json"
    return json.loads(path.read_text(encoding="utf-8"))


class TestPluginManifest:
    def test_manifest_has_required_fields(self):
        data = _plugin_json()
        for field in ("name", "version", "description"):
            assert field in data, f"plugin.json missing '{field}'"

    def test_manifest_has_commands_array(self):
        data = _plugin_json()
        assert "commands" in data
        assert isinstance(data["commands"], list)
        assert len(data["commands"]) > 0

    def test_manifest_has_skills_array(self):
        data = _plugin_json()
        assert "skills" in data
        assert isinstance(data["skills"], list)
        assert len(data["skills"]) > 0

    def test_each_command_has_name_and_description(self):
        for cmd in _plugin_json()["commands"]:
            assert "name" in cmd, f"Command missing 'name': {cmd}"
            assert "description" in cmd, f"Command missing 'description': {cmd}"

    def test_each_skill_has_name_path_and_description(self):
        data = _plugin_json()
        for skill in data["skills"]:
            assert "name" in skill, f"Skill missing 'name': {skill}"
            assert "path" in skill, f"Skill missing 'path': {skill}"
            assert "description" in skill, f"Skill missing 'description': {skill}"
            skill_path = REPO_ROOT / skill["path"]
            assert skill_path.exists(), f"Skill file not found: {skill_path}"

    def test_known_commands_present(self):
        command_names = {cmd["name"] for cmd in _plugin_json()["commands"]}
        expected = {"optimize", "generate-evaluator", "intake", "explain", "budget", "score", "analyze"}
        assert expected.issubset(command_names), (
            f"Missing commands in manifest: {expected - command_names}"
        )

