"""Normalization and validation for evaluator intake specifications."""

from __future__ import annotations

from collections.abc import Mapping
from math import floor, isfinite
from numbers import Real
from typing import Any

DEFAULT_ARTIFACT_CLASS = "general_text"
DEFAULT_EVALUATION_PATTERN = "judge"
DEFAULT_EXECUTION_MODE = "command"

ALLOWED_EVALUATION_PATTERNS = {
    "verification",
    "judge",
    "simulation",
    "composite",
}
ALLOWED_EXECUTION_MODES = {"command", "http"}

DEFAULT_QUALITY_DIMENSIONS: tuple[tuple[str, float], ...] = (
    ("correctness", 0.4),
    ("clarity", 0.35),
    ("conciseness", 0.25),
)


def normalize_intake_spec(data: Mapping[str, Any] | None) -> dict[str, Any]:
    """Normalize evaluator intake input and validate required structure."""
    if data is None:
        data = {}
    elif not isinstance(data, Mapping):
        raise ValueError("intake spec must be a mapping")

    artifact_class = _normalize_non_empty_string(
        data.get("artifact_class", DEFAULT_ARTIFACT_CLASS),
        field_name="artifact_class",
    )
    quality_dimensions = _normalize_quality_dimensions(data.get("quality_dimensions"))
    hard_constraints = _normalize_hard_constraints(data.get("hard_constraints", []))
    evaluation_pattern = _normalize_enum(
        data.get("evaluation_pattern", DEFAULT_EVALUATION_PATTERN),
        field_name="evaluation_pattern",
        allowed=ALLOWED_EVALUATION_PATTERNS,
    )
    execution_mode = _normalize_enum(
        data.get("execution_mode", DEFAULT_EXECUTION_MODE),
        field_name="execution_mode",
        allowed=ALLOWED_EXECUTION_MODES,
    )
    evaluator_cwd = _normalize_optional_string(
        data.get("evaluator_cwd"),
        field_name="evaluator_cwd",
    )

    return {
        "artifact_class": artifact_class,
        "quality_dimensions": quality_dimensions,
        "hard_constraints": hard_constraints,
        "evaluation_pattern": evaluation_pattern,
        "execution_mode": execution_mode,
        "evaluator_cwd": evaluator_cwd,
    }


def _normalize_non_empty_string(value: Any, *, field_name: str) -> str:
    if not isinstance(value, str):
        raise ValueError(f"{field_name} must be a string")
    normalized = value.strip()
    if not normalized:
        raise ValueError(f"{field_name} must be a non-empty string")
    return normalized


def _normalize_optional_string(value: Any, *, field_name: str) -> str | None:
    if value is None:
        return None
    if not isinstance(value, str):
        raise ValueError(f"{field_name} must be a string or None")
    normalized = value.strip()
    return normalized or None


def _normalize_enum(value: Any, *, field_name: str, allowed: set[str]) -> str:
    normalized = _normalize_non_empty_string(value, field_name=field_name).lower()
    if normalized not in allowed:
        options = ", ".join(f"'{item}'" for item in sorted(allowed))
        raise ValueError(f"{field_name} must be one of: {options}")
    return normalized


def _normalize_quality_dimensions(value: Any) -> list[dict[str, Any]]:
    if value is None:
        return [
            {"name": name, "weight": weight}
            for name, weight in DEFAULT_QUALITY_DIMENSIONS
        ]

    if not isinstance(value, list):
        raise ValueError("quality_dimensions must be a list of objects")
    if not value:
        raise ValueError("quality_dimensions must contain at least one dimension")

    names: list[str] = []
    seen_names: set[str] = set()
    weights: list[float] = []

    for idx, item in enumerate(value):
        if not isinstance(item, Mapping):
            raise ValueError(
                f"quality_dimensions[{idx}] must be an object with 'name' and 'weight'"
            )
        if "name" not in item:
            raise ValueError(f"quality_dimensions[{idx}] missing required field 'name'")
        if "weight" not in item:
            raise ValueError(f"quality_dimensions[{idx}] missing required field 'weight'")

        name = item["name"]
        if not isinstance(name, str):
            raise ValueError(f"quality_dimensions[{idx}].name must be a string")
        normalized_name = name.strip()
        if not normalized_name:
            raise ValueError(
                f"quality_dimensions[{idx}].name must be a non-empty string"
            )

        raw_weight = item["weight"]
        if isinstance(raw_weight, bool) or not isinstance(raw_weight, Real):
            raise ValueError(f"quality_dimensions[{idx}].weight must be numeric")

        weight = float(raw_weight)
        if not isfinite(weight):
            raise ValueError(f"quality_dimensions[{idx}].weight must be finite")
        if weight <= 0:
            raise ValueError(f"quality_dimensions[{idx}].weight must be > 0")

        if normalized_name in seen_names:
            raise ValueError(
                f"Duplicate quality dimension name: '{normalized_name}'"
            )
        seen_names.add(normalized_name)
        names.append(normalized_name)
        weights.append(weight)

    normalized_weights = _normalize_weights(weights)
    return [
        {"name": name, "weight": normalized_weights[idx]}
        for idx, name in enumerate(names)
    ]


def _normalize_weights(weights: list[float]) -> list[float]:
    total = sum(weights)
    scaled = [(weight / total) * 10000 for weight in weights]

    base_units = [int(floor(value)) for value in scaled]
    units_to_distribute = 10000 - sum(base_units)

    fractional_parts = [
        (scaled[idx] - base_units[idx], idx) for idx in range(len(weights))
    ]
    fractional_parts.sort(key=lambda item: (-item[0], item[1]))

    for _, idx in fractional_parts[:units_to_distribute]:
        base_units[idx] += 1

    return [unit / 10000 for unit in base_units]


def _normalize_hard_constraints(value: Any) -> list[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise ValueError("hard_constraints must be a list of strings")

    normalized: list[str] = []
    seen: set[str] = set()
    for idx, item in enumerate(value):
        if not isinstance(item, str):
            raise ValueError(f"hard_constraints[{idx}] must be a string")
        stripped = item.strip()
        if not stripped or stripped in seen:
            continue
        normalized.append(stripped)
        seen.add(stripped)

    return normalized

"""Load and normalize optimization spec files (TOML format).

Spec files allow saving repeatable optimization run configurations.
All paths in the spec are resolved relative to the spec file's location.
"""

from __future__ import annotations

import tomllib
from pathlib import Path
from typing import Any


class SpecLoadError(ValueError):
    """Raised when a spec file cannot be loaded or is invalid."""


def load_spec(spec_path: str | Path) -> dict[str, Any]:
    """Load and normalize a TOML spec file.

    Returns:
        Normalized spec dict with keys matching CLI argument names.

    Raises:
        SpecLoadError: If the file is missing, not valid TOML, or has invalid field types.
    """
    spec_path = Path(spec_path).expanduser().resolve()
    if not spec_path.exists():
        raise SpecLoadError(f"spec file not found: {spec_path}")

    try:
        with open(spec_path, "rb") as f:
            raw = tomllib.load(f)
    except tomllib.TOMLDecodeError as exc:
        raise SpecLoadError(f"invalid TOML in spec file '{spec_path}': {exc}") from exc

    spec_dir = spec_path.parent
    return _normalize_spec(raw, spec_dir=spec_dir)


def _normalize_spec(raw: dict[str, Any], *, spec_dir: Path) -> dict[str, Any]:
    opt = raw.get("optimization", {})
    evaluator = raw.get("evaluator", {})
    model = raw.get("model", {})
    intake_section = raw.get("intake", {})

    result: dict[str, Any] = {
        "seed_file": None,
        "objective": None,
        "background": None,
        "budget": None,
        "output": None,
        "evaluator_command": None,
        "evaluator_url": None,
        "evaluator_cwd": None,
        "judge_model": None,
        "proposer_model": None,
        "intake": None,
    }

    if "seed_file" in opt:
        seed_raw = opt["seed_file"]
        if not isinstance(seed_raw, str):
            raise SpecLoadError("optimization.seed_file must be a string")
        result["seed_file"] = str(_resolve_path(seed_raw, base=spec_dir))

    for str_key in ("objective", "background", "output"):
        if str_key in opt:
            value = opt[str_key]
            if not isinstance(value, str):
                raise SpecLoadError(f"optimization.{str_key} must be a string")
            result[str_key] = value

    if "budget" in opt:
        budget_raw = opt["budget"]
        if not isinstance(budget_raw, int) or budget_raw <= 0:
            raise SpecLoadError("optimization.budget must be a positive integer")
        result["budget"] = budget_raw

    if "command" in evaluator:
        cmd = evaluator["command"]
        if not isinstance(cmd, list) or not cmd:
            raise SpecLoadError("evaluator.command must be a non-empty list of strings")
        if not all(isinstance(c, str) for c in cmd):
            raise SpecLoadError("evaluator.command must be a list of strings")
        result["evaluator_command"] = cmd

    if "url" in evaluator:
        url = evaluator["url"]
        if not isinstance(url, str):
            raise SpecLoadError("evaluator.url must be a string")
        result["evaluator_url"] = url

    if "cwd" in evaluator:
        cwd_raw = evaluator["cwd"]
        if not isinstance(cwd_raw, str):
            raise SpecLoadError("evaluator.cwd must be a string")
        result["evaluator_cwd"] = str(_resolve_path(cwd_raw, base=spec_dir))

    if "judge" in model:
        judge = model["judge"]
        if not isinstance(judge, str):
            raise SpecLoadError("model.judge must be a string")
        result["judge_model"] = judge

    if "proposer" in model:
        proposer = model["proposer"]
        if not isinstance(proposer, str):
            raise SpecLoadError("model.proposer must be a string")
        result["proposer_model"] = proposer

    if intake_section:
        result["intake"] = dict(intake_section)

    return result


def _resolve_path(path_str: str, *, base: Path) -> Path:
    path = Path(path_str).expanduser()
    if not path.is_absolute():
        path = base / path
    return path

"""Canonical optimize output contract for CLI."""

from __future__ import annotations

from typing import Any


def build_optimize_summary(result: Any) -> dict[str, Any]:
    """Normalize GEPA result objects into a stable output schema."""
    scores = _coerce_numeric_list(getattr(result, "val_aggregate_scores", None))
    best_idx = _resolve_best_idx(result, scores)
    initial_score = scores[0] if scores else None
    latest_score = scores[-1] if scores else None
    best_score = scores[best_idx] if best_idx is not None else None

    top_diagnostics = _extract_top_diagnostics(result, best_idx, best_score)
    plateau_detected, plateau_guidance = _compute_plateau_guidance(scores)
    evaluator_failure_signal = _extract_evaluator_failure_signal(result, scores)

    summary: dict[str, Any] = {
        "best_artifact": getattr(result, "best_candidate", None),
        "total_metric_calls": getattr(result, "total_metric_calls", None),
        "score_summary": {
            "initial": initial_score,
            "latest": latest_score,
            "best": best_score,
            "delta_latest_vs_initial": _delta(latest_score, initial_score),
            "delta_best_vs_initial": _delta(best_score, initial_score),
            "num_candidates": len(scores),
        },
        "top_diagnostics": top_diagnostics,
        "plateau_detected": plateau_detected,
        "plateau_guidance": plateau_guidance,
        "evaluator_failure_signal": evaluator_failure_signal,
    }
    if evaluator_failure_signal is None:
        summary.pop("evaluator_failure_signal")
    return summary


def _coerce_numeric_list(raw: Any) -> list[float]:
    if not isinstance(raw, list):
        return []
    values: list[float] = []
    for value in raw:
        try:
            values.append(float(value))
        except (TypeError, ValueError):
            continue
    return values


def _resolve_best_idx(result: Any, scores: list[float]) -> int | None:
    if not scores:
        return None
    raw_idx = getattr(result, "best_idx", None)
    if isinstance(raw_idx, int) and 0 <= raw_idx < len(scores):
        return raw_idx
    return max(range(len(scores)), key=lambda idx: scores[idx])


def _extract_top_diagnostics(
    result: Any,
    best_idx: int | None,
    best_score: float | None,
) -> list[dict[str, float]]:
    raw = getattr(result, "val_aggregate_subscores", None)
    if (
        isinstance(raw, list)
        and best_idx is not None
        and best_idx < len(raw)
        and isinstance(raw[best_idx], dict)
    ):
        pairs: list[tuple[str, float]] = []
        for key, value in raw[best_idx].items():
            try:
                pairs.append((str(key), float(value)))
            except (TypeError, ValueError):
                continue
        pairs.sort(key=lambda item: item[1], reverse=True)
        if pairs:
            return [{"name": name, "value": value} for name, value in pairs[:3]]

    if best_score is None:
        return []
    return [{"name": "overall_score", "value": best_score}]


def _compute_plateau_guidance(scores: list[float]) -> tuple[bool, str]:
    if len(scores) < 3:
        return (
            False,
            "Run more optimization iterations before assessing plateau behavior.",
        )

    recent = scores[-5:] if len(scores) >= 5 else scores
    spread = max(recent) - min(recent)
    total_gain = scores[-1] - scores[0]
    plateau = spread < 0.01 and total_gain < 0.02
    if plateau:
        return (
            True,
            "Scores have flattened. Improve evaluator diagnostics, refine the objective, or increase budget.",
        )
    return (
        False,
        "No strong plateau detected. Continue iterating or tighten constraints to target specific gains.",
    )


def _extract_evaluator_failure_signal(
    result: Any,
    scores: list[float],
) -> dict[str, Any] | None:
    metric_signal = _extract_failure_metric_signal(
        getattr(result, "val_aggregate_subscores", None)
    )
    if metric_signal is not None:
        return metric_signal

    if len(scores) >= 3 and all(abs(score) < 1e-12 for score in scores):
        return {
            "kind": "repeated_zero_scores",
            "message": (
                "All candidate scores are 0.0 across optimization iterations. "
                "This often indicates evaluator command/runtime or JSON contract failures."
            ),
            "num_candidates": len(scores),
        }

    return None


def _extract_failure_metric_signal(raw: Any) -> dict[str, Any] | None:
    if not isinstance(raw, list):
        return None

    failure_tokens = ("error", "fail", "timeout", "invalid", "exception")
    max_by_metric: dict[str, float] = {}
    latest_by_metric: dict[str, float] = {}

    for idx, item in enumerate(raw):
        if not isinstance(item, dict):
            continue
        for key, value in item.items():
            metric_name = str(key)
            lower_name = metric_name.lower()
            if not any(token in lower_name for token in failure_tokens):
                continue
            try:
                numeric = float(value)
            except (TypeError, ValueError):
                continue
            previous_max = max_by_metric.get(metric_name)
            if previous_max is None or numeric > previous_max:
                max_by_metric[metric_name] = numeric
            if idx == len(raw) - 1:
                latest_by_metric[metric_name] = numeric

    if not max_by_metric:
        return None

    active_metrics = [
        {
            "name": name,
            "latest": round(latest_by_metric.get(name, 0.0), 6),
            "max": round(max_value, 6),
        }
        for name, max_value in max_by_metric.items()
        if max_value > 0.0
    ]
    if not active_metrics:
        return None

    active_metrics.sort(key=lambda item: item["max"], reverse=True)
    return {
        "kind": "failure_diagnostic_metrics",
        "message": (
            "Evaluator diagnostics include failure-oriented metrics. "
            "Verify evaluator command/runtime wiring and output contract."
        ),
        "metrics": active_metrics[:3],
    }


def _delta(new: float | None, old: float | None) -> float | None:
    if new is None or old is None:
        return None
    return round(new - old, 6)

#!/usr/bin/env python3
"""Live integration test -- RED-GREEN orchestrator.

Run one GREEN (optimize) or RED (multi-provider score) phase and output
structured JSON. Designed to be driven by Claude Code as an interactive observer.

Usage:
    # GREEN phase: optimize an artifact
    python scripts/live_integration.py --phase green \
        --artifact skills/generate-evaluator/SKILL.md \
        --evaluator-command bash evaluators/skill_clarity.sh \
        --budget 15 --objective "Improve clarity" \
        --run-dir integration_runs

    # RED phase: score with multiple providers
    python scripts/live_integration.py --phase red \
        --artifact skills/generate-evaluator/SKILL.md \
        --objective "Score skill quality" \
        --providers openai/gpt-5.1 anthropic/claude-sonnet-4-5-20250929 \
        --evaluator-command bash evaluators/skill_clarity.sh
"""
from __future__ import annotations

import argparse
import json
import subprocess
import sys
from pathlib import Path


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(
        prog="live-integration",
        description="RED-GREEN integration test orchestrator",
    )
    parser.add_argument(
        "--phase",
        required=True,
        choices=["green", "red"],
        help="Which phase to run",
    )
    parser.add_argument("--artifact", required=True, help="Path to artifact file")
    parser.add_argument("--objective", help="Natural language objective")
    parser.add_argument("--budget", type=int, default=15, help="GREEN: max evaluator calls")
    parser.add_argument("--run-dir", help="GREEN: directory to save run artifacts")
    parser.add_argument(
        "--model",
        help="GREEN: LLM model string for the proposer (e.g. 'openai/gpt-4o-mini')",
    )
    parser.add_argument(
        "--providers",
        nargs="+",
        help="RED: LLM provider model strings for multi-provider scoring",
    )
    parser.add_argument(
        "--judge-model",
        help="GREEN: LLM judge model for meta-evaluator optimization",
    )
    parser.add_argument(
        "--judge-objective",
        help="GREEN: override objective for the LLM judge",
    )
    parser.add_argument("--round", type=int, default=1, help="Current round number")
    parser.add_argument("--baseline", type=float, help="Baseline score for comparison")
    parser.add_argument(
        "--evaluator-url",
        help="HTTP evaluator URL (mutually exclusive with --evaluator-command)",
    )
    # MUST be last nargs="+" argument to avoid greedy consumption of subsequent flags
    parser.add_argument(
        "--evaluator-command",
        nargs="+",
        help="Command evaluator for GREEN phase or RED command scoring",
    )

    args = parser.parse_args(argv)

    # Detect flags accidentally swallowed by --evaluator-command nargs="+"
    if args.evaluator_command:
        swallowed = [t for t in args.evaluator_command if t.startswith("--")]
        if swallowed:
            print(json.dumps({
                "error": (
                    f"--evaluator-command consumed flag-like tokens: {swallowed}. "
                    "Place --evaluator-command as the LAST argument."
                ),
            }))
            return 1

    if args.evaluator_command and args.evaluator_url:
        print(json.dumps({
            "error": "--evaluator-command and --evaluator-url are mutually exclusive",
        }))
        return 1

    if args.providers and not args.objective:
        print(json.dumps({
            "error": "--providers requires --objective for LLM judge scoring",
        }))
        return 1

    if args.phase == "green":
        return _run_green(args)
    elif args.phase == "red":
        return _run_red(args)
    return 1


def _run_green(args: argparse.Namespace) -> int:
    """Run GREEN phase: optimize artifact, return structured results."""
    artifact_path = Path(args.artifact)
    if not artifact_path.exists():
        print(json.dumps({"error": f"Artifact not found: {args.artifact}"}))
        return 1

    # Score the artifact before optimization
    if args.evaluator_url:
        initial_score = _score_with_url(artifact_path, args.evaluator_url)
    else:
        initial_score = _score_with_command(artifact_path, args.evaluator_command)

    # Build optimize command
    cmd = [
        sys.executable, "-m", "optimize_anything.cli",
        "optimize", str(artifact_path),
        "--budget", str(args.budget),
        "--diff",
    ]
    if args.model:
        cmd.extend(["--model", args.model])
    if args.judge_model:
        cmd.extend(["--judge-model", args.judge_model])
    if args.judge_objective:
        cmd.extend(["--judge-objective", args.judge_objective])
    if args.objective:
        cmd.extend(["--objective", args.objective])
    if args.run_dir:
        cmd.extend(["--run-dir", args.run_dir])
    # --evaluator-command must be last due to nargs="+" greedy parsing
    if args.evaluator_command:
        cmd.extend(["--evaluator-command"] + args.evaluator_command)
    elif args.evaluator_url:
        cmd.extend(["--evaluator-url", args.evaluator_url])

    timeout = max(300, args.budget * 30)
    try:
        proc = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            timeout=timeout,
        )
    except subprocess.TimeoutExpired:
        print(json.dumps({"phase": "green", "error": f"optimize timed out after {timeout}s"}))
        return 1

    if proc.returncode != 0:
        print(json.dumps({
            "phase": "green",
            "error": f"optimize failed (rc={proc.returncode})",
            "stderr": proc.stderr[:2000],
        }))
        return 1

    optimize_result = _extract_json_from_output(proc.stdout)
    if optimize_result is None:
        print(json.dumps({
            "phase": "green",
            "error": "optimize output not valid JSON",
            "stdout": proc.stdout[:2000],
        }))
        return 1

    # Detect zero proposals — usually means --model is wrong or API key missing
    score_summary = optimize_result.get("score_summary", {})
    num_candidates = score_summary.get("num_candidates", 0)
    if num_candidates == 0:
        print(json.dumps({
            "phase": "green",
            "error": "optimizer generated no proposals — check --model flag and API keys",
            "run_dir": optimize_result.get("run_dir"),
        }))
        return 1
    if num_candidates == 1:
        print("Warning: only 1 candidate evaluated (seed only) — consider increasing --budget or checking --model", file=sys.stderr)

    # Extract optimized score from summary
    optimized_score = score_summary.get("best", initial_score)
    metric_calls = optimize_result.get("total_metric_calls", 0)

    # Count diff lines from stderr
    diff_add = sum(1 for l in proc.stderr.split("\n") if l.startswith("+") and not l.startswith("+++"))
    diff_del = sum(1 for l in proc.stderr.split("\n") if l.startswith("-") and not l.startswith("---"))
    diff_summary = f"+{diff_add} -{diff_del}"

    baseline = args.baseline if args.baseline is not None else (initial_score if initial_score is not None else None)

    result = {
        "phase": "green",
        "round": args.round,
        "artifact": args.artifact,
        "green": {
            "initial_score": initial_score,
            "optimized_score": optimized_score,
            "metric_calls": metric_calls,
            "diff_summary": diff_summary,
            "best_artifact_preview": str(optimize_result.get("best_artifact", ""))[:500],
            "run_dir": optimize_result.get("run_dir"),
        },
        "baseline": args.baseline,
        "improved": optimized_score is not None and baseline is not None and optimized_score > baseline,
    }

    print(json.dumps(result, indent=2, default=str))
    return 0


def _run_red(args: argparse.Namespace) -> int:
    """Run RED phase: score artifact with multiple evaluator backends."""
    artifact_path = Path(args.artifact)
    if not artifact_path.exists():
        print(json.dumps({"error": f"Artifact not found: {args.artifact}"}))
        return 1

    scores = {}

    # 1. Command evaluator score (if provided)
    if args.evaluator_command:
        cmd_score = _score_with_command(artifact_path, args.evaluator_command)
        scores["command"] = cmd_score
    elif args.evaluator_url:
        url_score = _score_with_url(artifact_path, args.evaluator_url)
        scores["http"] = url_score

    # 2. LLM judge scores (one per provider)
    providers = args.providers or []
    for provider in providers:
        judge_score = _score_with_judge(artifact_path, provider, args.objective)
        # Use a clean key: "openai/gpt-5.1" -> "openai_gpt_5_1"
        key = provider.replace("/", "_").replace("-", "_").replace(".", "_")
        scores[key] = judge_score

    # Cross-provider analysis
    judge_scores = [v for k, v in scores.items() if k != "command" and v is not None]
    cross_provider_delta = (
        round(max(judge_scores) - min(judge_scores), 4) if len(judge_scores) >= 2 else 0.0
    )

    all_scores = [v for v in scores.values() if v is not None]
    if not all_scores:
        print(json.dumps({
            "phase": "red",
            "error": "all evaluators returned None — check provider credentials and connectivity",
            "scores": scores,
        }))
        return 1
    avg_score = round(sum(all_scores) / len(all_scores), 4)

    baseline = args.baseline if args.baseline is not None else 0.0

    result = {
        "phase": "red",
        "round": args.round,
        "artifact": args.artifact,
        "red": {
            "scores": scores,
            "cross_provider_delta": cross_provider_delta,
            "average_score": avg_score,
        },
        "baseline": args.baseline,
        "improved": avg_score > baseline,
    }

    print(json.dumps(result, indent=2, default=str))
    return 0


def _extract_json_from_output(output: str) -> dict | None:
    """Extract the last JSON object from mixed stdout output.

    The gepa engine prints iteration progress lines to stdout before the
    CLI prints its JSON summary. This function finds and parses that
    trailing JSON object.
    """
    # Try parsing the entire output first (fast path)
    try:
        return json.loads(output)
    except json.JSONDecodeError:
        pass

    # Find the last '{' that starts a valid JSON object
    # Search backwards for the outermost opening brace
    idx = output.rfind("\n{")
    if idx >= 0:
        try:
            return json.loads(output[idx + 1:])
        except json.JSONDecodeError:
            pass

    # Try from the very start if output starts with '{'
    if output.lstrip().startswith("{"):
        try:
            return json.loads(output.lstrip())
        except json.JSONDecodeError:
            pass

    return None


def _score_with_command(
    artifact_path: Path,
    evaluator_command: list[str] | None,
) -> float | None:
    """Score artifact using command evaluator via CLI."""
    if not evaluator_command:
        return None

    cmd = [
        sys.executable, "-m", "optimize_anything.cli",
        "score", str(artifact_path),
        "--evaluator-command",
    ] + evaluator_command

    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
        if proc.returncode != 0:
            print(f"Warning: command evaluator exited with code {proc.returncode}", file=sys.stderr)
            return None
        result = json.loads(proc.stdout)
        return result.get("score")
    except subprocess.TimeoutExpired:
        print("Warning: command evaluator timed out after 30s", file=sys.stderr)
        return None
    except json.JSONDecodeError as exc:
        print(f"Warning: command evaluator returned invalid JSON: {exc}", file=sys.stderr)
        return None
    except Exception as exc:
        print(f"Warning: command evaluator failed: {type(exc).__name__}: {exc}", file=sys.stderr)
        return None


def _score_with_url(
    artifact_path: Path,
    evaluator_url: str,
) -> float | None:
    """Score artifact using HTTP evaluator via CLI."""
    cmd = [
        sys.executable, "-m", "optimize_anything.cli",
        "score", str(artifact_path),
        "--evaluator-url", evaluator_url,
    ]

    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
        if proc.returncode != 0:
            print(f"Warning: HTTP evaluator exited with code {proc.returncode}", file=sys.stderr)
            if proc.stderr:
                print(f"  stderr: {proc.stderr.strip()[:200]}", file=sys.stderr)
            return None
        result = json.loads(proc.stdout)
        return result.get("score")
    except subprocess.TimeoutExpired:
        print("Warning: HTTP evaluator timed out after 30s", file=sys.stderr)
        return None
    except json.JSONDecodeError as exc:
        print(f"Warning: HTTP evaluator returned invalid JSON: {exc}", file=sys.stderr)
        return None
    except Exception as exc:
        print(f"Warning: HTTP evaluator failed: {type(exc).__name__}: {exc}", file=sys.stderr)
        return None


def _score_with_judge(
    artifact_path: Path,
    model: str,
    objective: str | None,
) -> float | None:
    """Score artifact using LLM judge via CLI."""
    if not objective:
        return None

    cmd = [
        sys.executable, "-m", "optimize_anything.cli",
        "score", str(artifact_path),
        "--judge-model", model,
        "--objective", objective,
    ]

    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=120)
        if proc.returncode != 0:
            print(f"Warning: judge {model} exited with code {proc.returncode}", file=sys.stderr)
            return None
        result = json.loads(proc.stdout)
        return result.get("score")
    except subprocess.TimeoutExpired:
        print(f"Warning: judge {model} timed out after 120s", file=sys.stderr)
        return None
    except json.JSONDecodeError as exc:
        print(f"Warning: judge {model} returned invalid JSON: {exc}", file=sys.stderr)
        return None
    except Exception as exc:
        print(f"Warning: judge {model} failed: {type(exc).__name__}: {exc}", file=sys.stderr)
        return None


if __name__ == "__main__":
    sys.exit(main())

"""Tests for evaluator intake normalization and validation."""

from __future__ import annotations

import pytest

from optimize_anything.intake import normalize_intake_spec


@pytest.mark.parametrize("data", [None, {}])
def test_defaults_from_none_or_empty_input(data):
    assert normalize_intake_spec(data) == {
        "artifact_class": "general_text",
        "quality_dimensions": [
            {"name": "correctness", "weight": 0.4},
            {"name": "clarity", "weight": 0.35},
            {"name": "conciseness", "weight": 0.25},
        ],
        "hard_constraints": [],
        "evaluation_pattern": "judge",
        "execution_mode": "command",
        "evaluator_cwd": None,
    }


def test_invalid_execution_mode_and_evaluation_pattern():
    with pytest.raises(ValueError, match="execution_mode must be one of"):
        normalize_intake_spec({"execution_mode": "grpc"})

    with pytest.raises(ValueError, match="evaluation_pattern must be one of"):
        normalize_intake_spec({"evaluation_pattern": "pairwise"})


@pytest.mark.parametrize(
    "pattern",
    ["verification", "judge", "simulation", "composite"],
)
def test_supported_evaluation_patterns(pattern):
    normalized = normalize_intake_spec({"evaluation_pattern": pattern})
    assert normalized["evaluation_pattern"] == pattern


def test_invalid_quality_dimensions_structure():
    with pytest.raises(ValueError, match="quality_dimensions must be a list of objects"):
        normalize_intake_spec({"quality_dimensions": "not-a-list"})

    with pytest.raises(ValueError, match="quality_dimensions\\[0\\] missing required field 'name'"):
        normalize_intake_spec({"quality_dimensions": [{"weight": 1.0}]})

    with pytest.raises(ValueError, match="quality_dimensions\\[0\\].name must be a non-empty string"):
        normalize_intake_spec({"quality_dimensions": [{"name": "  ", "weight": 1.0}]})


def test_invalid_quality_dimensions_non_numeric_weight():
